const express = require('express');
const app = express();
const mongoose = require('mongoose');

// Connect to MongoDB
mongoose.connect('mongodb://localhost/mydatabase', { useNewUrlParser: true, useUnifiedTopology: true });

// Define a schema for the data collection
const dataSchema = new mongoose.Schema({
  name: String,
  age: Number,
  email: String
});

// Create a model from the schema
const Data = mongoose.model('Data', dataSchema);

// Middleware to parse JSON requests
app.use(express.json());

// API endpoint to query data
app.post('/query', async (req, res) => {
  try {
    const filters = req.body;
    const results = await Data.find(filters);
    res.json(results);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error querying database' });
  }
});

// API endpoint to query data with pagination
app.post('/query/paginate', async (req, res) => {
  try {
    const filters = req.body;
    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 10;
    const skip = (page - 1) * limit;
    const results = await Data.find(filters).skip(skip).limit(limit);
    res.json(results);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error querying database' });
  }
});

// API endpoint to query data with aggregation
app.post('/query/aggregate', async (req, res) => {
  try {
    const filters = req.body;
    const pipeline = [
      { $match: filters },
      { $group: { _id: null, count: { $sum: 1 } } }
    ];
    const results = await Data.aggregate(pipeline);
    res.json(results);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error querying database' });
  }
});

// Start the server
const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});